// Twisted Spinning Top — a fluted, tapered body that twists down to a fine
// spin point, capped by a short knob/stem you pinch and flick.
//
// Technique: build a fluted circular CrossSection (a circle modulated by a
// cosine so it gains N shallow scallops), then `extrude` it DOWNWARD-shaped:
// we extrude UP with scaleTop≈0 so it tapers to a point at the top, give it a
// high-nDiv twist so the flutes spiral, then flip the whole body so the point
// lands at the bottom and the wide rounded shoulder is up. A short cylindrical
// stem overlaps the top as the flick knob.
const { Manifold, CrossSection } = api;

const p = api.params({
  bodyRadius: { type: 'number', default: 16, min: 8,  max: 28, step: 0.5, unit: 'mm', label: 'Body radius' },
  bodyHeight: { type: 'number', default: 30, min: 18, max: 50, step: 1,   unit: 'mm', label: 'Body height' },
  fluteCount: { type: 'int',    default: 8,  min: 4,  max: 14,             label: 'Flute count' },
  twistDeg:   { type: 'number', default: 200, min: 60, max: 360, step: 10, unit: '°', label: 'Twist' },
});

// --- Fluted profile: a circle with `fluteCount` shallow scallops ---------
// Polar radius r(θ) = R * (1 + amp·cos(N·θ)). amp small => gentle flutes/grips.
const fluteAmp = 0.14;                 // depth of the flutes as a fraction of R
const profSegs = Math.max(96, p.fluteCount * 16); // smooth scallops
const pts = [];
for (let i = 0; i < profSegs; i++) {
  const a = (i / profSegs) * Math.PI * 2;
  const r = p.bodyRadius * (1 + fluteAmp * Math.cos(p.fluteCount * a));
  pts.push([r * Math.cos(a), r * Math.sin(a)]);
}
const fluted = CrossSection.ofPolygons([pts]);

// --- Body: extrude the flutes upward, tapering to a near-point, twisting ---
// scaleTop small-but-nonzero keeps a crisp spin tip without a degenerate vertex.
const tipScale = 0.055;
const twistSlices = 128;               // high nDiv so the spiral reads smoothly
let body = fluted.extrude(p.bodyHeight, twistSlices, p.twistDeg, tipScale);

// Flip so the tapered point is at the BOTTOM (z low) and the wide part is up,
// then drop the tip to z=0 so it sits on the ground like a real top.
body = body.rotate([180, 0, 0]).translate([0, 0, p.bodyHeight]);

// Rounded shoulder: a flattened sphere cap blended onto the wide top so the
// body reads as a classic domed top rather than a sharp-edged cylinder rim.
const shoulder = Manifold.sphere(p.bodyRadius)
  .scale([1, 1, 0.45])
  .translate([0, 0, p.bodyHeight - p.bodyRadius * 0.3]);
body = body.add(shoulder);

// --- Stem / flick knob: a short cylinder + rounded cap, overlapping the top --
const stemR = p.bodyRadius * 0.22;
const stemH = p.bodyHeight * 0.32;
const stemBaseZ = p.bodyHeight - 1.5;  // sink 1.5 units in so it unions cleanly
const stemShaft = Manifold.cylinder(stemH, stemR * 1.25, stemR)
  .translate([0, 0, stemBaseZ]);
const stemCap = Manifold.sphere(stemR * 1.15)
  .translate([0, 0, stemBaseZ + stemH]);
const stem = stemShaft.add(stemCap);

// --- Self-colored assembly -------------------------------------------------
return api.labeledUnion([
  { name: 'body', shape: body, color: '#2b8cff' },  // vibrant blue body
  { name: 'stem', shape: stem, color: '#ffd23f' },  // contrasting amber knob
]);

